) VALUES (
  'ffea930a-c230-57ec-a18f-26f343c54835', 32, 'Breeding', NULL, 'SMALL_RUMINANT', 'Pregnant', 'Database',
  NULL, 'Check "Tag Number" for Lambing', NULL, 'تحقق من Tag Number للولادة',
  'A doe within 12 - 16 hours of kidding will wiggle its tail several times. During this time, the doe will often start "baby talking" and dig and stir the bedding in her pen or isolate herself from the herd. It will be uneasy and may lie down and get up frequently.
Then move to a Maternity Pen', '‏تقوم العنزة خلال 12 إلى 16 ساعة قبل الولادة بهز ذيلها عدة مرات. وخلال هذه الفترة، تبدأ غالبًا بإصدار أصوات مميزة ("تتحدث مع صغيرها")، وتقوم بالحفر وتحريك الفرشة في مكانها أو تعزل نفسها عن القطيع. تظهر عليها علامات القلق وقد تستلقي وتنهض بشكل متكرر.
بعدها يجب نقلها إلى حظيرة الولادة.', 'TagNumber', '1 week before the estmimated due Date', NULL,
  NULL, 'SYSTEM', 'HIGH', NULL, NULL, ARRAY['IN_APP', 'PUSH'],
  TRUE, TRUE, TRUE, NULL
);
