  'be2a3e1d-97a3-5282-88d3-e8961f02c080', 33, 'Breeding', NULL, 'CATTLE', 'Given Birth', 'Database',
  NULL, 'Ready to Breed - Check for Heat', NULL, 'جاهزة للتلقيح – تحقق من دورة الشبق',
  'The cow is not 45 Days since given birth and we should start preparing  her for breeding , please check for signs of heat.', 'البقرة لم يمر عليها 45 يومًا منذ الولادة، ويجب أن نبدأ بتحضيرها للتلقيح. يُرجى مراقبتها بحثًا عن علامات الشبق.', 'TagNumber', '45 Days after Birth', NULL,
  NULL, 'SYSTEM', 'HIGH', NULL, NULL, ARRAY['IN_APP'],
  TRUE, TRUE, TRUE, NULL
);
INSERT INTO notification_task_definitions (
  id, task_id, category, country_code, species, current_state, source,
  notification_text, task_name, notification_text_ar, task_name_ar,
  expanded_detail, expanded_detail_ar, level, trigger_event, trigger_criteria,
  due_date_rule, action_by, priority, frequency, system_action, channels,
  go_live, is_active, default_enabled, notes
) VALUES (
  '7aa60ee6-e1ba-5027-988f-34223ae44411', 35, 'Medical', NULL, 'SMALL_RUMINANT', 'Pregnant', 'Database',
  NULL, 'Watch for Birth', NULL, 'راقب الولادة',
  'When animal is born 
CREATE EMERGENCY PROCEDURE FOR LAMB NOT BREATHING/FEEDING
Wash udder and hind parts of the doe at the end of kidding.
Break umbilical cord if necessary
dip the navel in a 7% tincture of iodine
spray the hooves with a 7% tincture of iodine
Open the does teat

Weigh newborn lamb
Apply temporary tag
Create animal record(s)
Tie the umbilical cord
Check if lamb is able to stand and suckle within first 15 min', 'عند ولادة الحيوان:

إنشاء إجراء طارئ لحالات عدم تنفس/رضاعة الخروف حديث الولادة
غسل الضرع والأجزاء الخلفية للأم بعد انتهاء الولادة
قطع الحبل السري إذا لزم الأمر
غمس السرة في صبغة يود 7%
رش الحوافر بصبغة يود 7%
فتح ضرع الأم والتأكد من خروج الحليب

وزن الخروف حديث الولادة
وضع بطاقة تعريف مؤقتة
إنشاء سجل للحيوان
ربط الحبل السري
التأكد من قدرة الخروف على الوقوف والرضاعة خلال أول 15 دقيقة', 'TagNumber', '2 Days before Due Date', NULL,
  NULL, 'SYSTEM', 'HIGH', NULL, NULL, ARRAY['IN_APP', 'PUSH'],
  TRUE, TRUE, TRUE, NULL
);
