INSERT INTO notification_task_definitions (
  id, task_id, category, country_code, species, current_state, source,
  notification_text, task_name, notification_text_ar, task_name_ar,
  expanded_detail, expanded_detail_ar, level, trigger_event, trigger_criteria,
  due_date_rule, action_by, priority, frequency, system_action, channels,
  go_live, is_active, default_enabled, notes
) VALUES (
  '995a4f4a-07d7-52ec-85b1-05ac59e44ed1', 68, 'Vaccinations', NULL, 'ALL', 'Vaccine not registered', 'Database',
  NULL, 'Clostridium Vaccination Due', NULL, 'اللقاح ضد الكلوستريديوم مستحق الآن',
  'Newborn animals should be vaccinated on their eighth week of age then they will be revaccinated after 6-4 weeks
·         Mothers should be vaccinated during their second semester of pregnancy, and then they will be revaccinated after 6-4 weeks (provided that the second vaccination should be twoweeks before delivery)
·         Animals or babies that are first time to be vaccinated should be revaccinated after 6-4 weeks
·         Babies of the unvaccinated mothers should be vaccinated after delivery then they will be revaccinated after 6-4 weeks', 'يجب تلقيح الحيوانات حديثة الولادة في الأسبوع الثامن من عمرها، ثم يُعاد تلقيحها بعد 4 إلى 6 أسابيع.

يجب تلقيح الأمهات خلال الثلث الثاني من الحمل، ثم يُعاد تلقيحهن بعد 4 إلى 6 أسابيع، بشرط أن يتم التلقيح الثاني قبل الولادة بأسبوعين.

الحيوانات أو الصغار الذين يتم تلقيحهم لأول مرة يجب أن يُعاد تلقيحهم بعد 4 إلى 6 أسابيع.

صغار الأمهات غير الملقحات يجب أن يُلقحوا بعد الولادة مباشرة، ثم يُعاد تلقيحهم بعد 4 إلى 6 أسابيع.', NULL, 'Send march/April & Sept/October', 'Send if no vaccination recorded during the time period',
  NULL, 'SYSTEM', 'HIGH', 'Weekly', NULL, ARRAY['IN_APP', 'PUSH'],
  TRUE, TRUE, TRUE, 'Start with basic, Later workout which animals should be vaccinated'
);
